package org.example.pages;

import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.support.ui.ExpectedConditions;

import java.util.List;

public class SearchResultsPage extends BasePage {

    private final By languageMenu = By.xpath("//summary[contains(., 'Language')] | //span[text()='Language']/parent::button");
    private final By sortButton = By.xpath("//summary[contains(., 'Sort')] | //button[contains(., 'Sort')]");
    private final By mostStarsOption = By.xpath("//span[contains(text(), 'Most stars')] | //label[contains(text(), 'Most stars')] | //div[contains(text(), 'Most stars')]");

    public SearchResultsPage(WebDriver driver) {
        super(driver);
    }

    public boolean isSpecificResultFound(String repoPath) {
        By specificLink = By.xpath("//a[contains(@href, '/" + repoPath + "')]");
        waitForElementVisible(specificLink);
        return true;
    }

    public SearchResultsPage filterByLanguageJava() {
        try {
            waitForElementClickable(languageMenu).click();
            By javaFilterMenu = By.xpath("//span[text()='Java'] | //a[contains(text(), 'Java')]");
            waitForElementClickable(javaFilterMenu).click();
        } catch (Exception e) {
            By javaFilterDirect = By.xpath("//a[contains(@data-label, 'Java')] | //span[text()='Java']");
            waitForElementClickable(javaFilterDirect).click();
        }
        try { Thread.sleep(2000); } catch (Exception ignored) {}
        return this;
    }

    public List<WebElement> getLanguageResults() {
        By javaLangs = By.xpath("//li//span[@itemprop='programmingLanguage'] | //div[contains(@class, 'search-match')]//span[contains(text(), 'Java')] | //span[contains(text(), 'Java')]");
        return wait.until(ExpectedConditions.presenceOfAllElementsLocatedBy(javaLangs));
    }

    public SearchResultsPage sortByMostStars() {
        waitForElementClickable(sortButton).click();
        waitForElementClickable(mostStarsOption).click();
        try { Thread.sleep(2000); } catch (Exception ignored) {}
        return this;
    }

    public List<WebElement> getStarResults() {
        By stars = By.xpath("//a[contains(@href, '/stargazers')] | //svg[contains(@class, 'octicon-star')]/parent::div/span | //span[contains(@aria-label, 'star')]");
        return wait.until(ExpectedConditions.presenceOfAllElementsLocatedBy(stars));
    }
}

package org.example.pages;

import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.support.ui.ExpectedConditions;

import java.util.List;

public class SearchResultsPage extends BasePage {

    private final By languageMenu = By.xpath("//summary[contains(., 'Language')] | //span[text()='Language']/parent::button");
    private final By sortButton = By.xpath("//summary[contains(., 'Sort')] | //button[contains(., 'Sort')]");
    private final By mostStarsOption = By.xpath("//span[contains(text(), 'Most stars')] | //label[contains(text(), 'Most stars')] | //div[contains(text(), 'Most stars')]");

    public SearchResultsPage(WebDriver driver) {
        super(driver);
    }

    public boolean isSpecificResultFound(String repoPath) {
        By specificLink = By.xpath("//a[contains(@href, '/" + repoPath + "')]");
        waitForElementVisible(specificLink);
        return true;
    }

    public SearchResultsPage filterByLanguageJava() {
        try {
            waitForElementClickable(languageMenu).click();
            By javaFilterMenu = By.xpath("//div[@title='Java'] | //a[contains(@href, 'language%3AJava')] | //span[text()='Java']");
            waitForElementClickable(javaFilterMenu).click();
        } catch (Exception e) {
            By javaFilterDirect = By.xpath("//div[@title='Java'] | //a[contains(@href, 'language%3AJava')] | //span[text()='Java']");
            waitForElementClickable(javaFilterDirect).click();
        }
        try { Thread.sleep(2000); } catch (Exception ignored) {}
        return this;
    }

    public List<WebElement> getLanguageResults() {
        By javaLangs = By.xpath("//li[contains(@class, 'Footer-module__footerItem')]//span[contains(@aria-label, 'Java language')] | //li//span[@itemprop='programmingLanguage'] | //div[contains(@class, 'search-match')]//span[contains(text(), 'Java')] | //span[text()='Java']");
        return wait.until(ExpectedConditions.presenceOfAllElementsLocatedBy(javaLangs));
    }

    public SearchResultsPage sortByMostStars() {
        waitForElementClickable(sortButton).click();
        waitForElementClickable(mostStarsOption).click();
        try { Thread.sleep(2000); } catch (Exception ignored) {}
        return this;
    }

    public List<WebElement> getStarResults() {
        By stars = By.xpath("//a[contains(@href, '/stargazers')] | //svg[contains(@class, 'octicon-star')]/parent::div/span | //span[contains(@aria-label, 'star')]");
        return wait.until(ExpectedConditions.presenceOfAllElementsLocatedBy(stars));
    }
}
